function [Vref] = func_SineSpeed(Index, MPCParameters) % 输出子函数中的正弦速度曲线生成子函数
    T = 50; 
    freq = 1/T; 
    Amplit = 10;
    offst = 20; 
    Ts = MPCParameters.Ts; 
    Np = MPCParameters.Np; 
    Vref = cell(Np,1);
    t0 = Index*Ts;
    for i = 1:1:Np
        t = t0 + i*Ts;
        Vref{i,1}   =   Amplit*sin(2*pi*freq*t) + offst;   
    end

function [Vref] = func_ConstantSpeed(InitialGapflag, MPCParameters) % 输出子函数中的阶梯速度曲线生成子函数    
    Ts = MPCParameters.Ts;
    Np = MPCParameters.Np;
    Vref = cell(Np,1);
    % 自定义阶梯的形式
    if InitialGapflag < 400
        Vset = 10;
    else
        if InitialGapflag < 800
            Vset = 10;
        else
            if InitialGapflag < 1500
                Vset = 20;
            else
                Vset = 5;
            end
        end
    end

    for i = 1:1:Np
        Vref{i,1}   =   Vset;   
    end

function[H, f, g] = func_Update_H_f(kesi, SpeedProfile, PHI, THETA, MPCParameters)  % 输出子函数中的目标函数子函数
    Np = MPCParameters.Np;
    Nc = MPCParameters.Nc;   
    Q  = MPCParameters.Q;
    R  = MPCParameters.R;
    Qq = kron(eye(Np),Q); 
    Rr = kron(eye(Nc),R); 
    Vref = cell2mat(SpeedProfile); 
    error = PHI * kesi;    
    H = THETA'*Qq*THETA + Rr;  
    f = (error' - Vref')*Qq*THETA;
    g = f';

function  [A, b, Aeq, beq, lb, ub] = func_Constraints_du_quadprog(MPCParameters, um)  % 输出子函数中的基于quadprog求解器的约束优化子函数
    Np   = MPCParameters.Np;
    Nc   = Np;    
    dumax = MPCParameters.dumax;
    umin = MPCParameters.umin;  
    umax = MPCParameters.umax;  
    Umin = kron(ones(Nc,1),umin);
    Umax = kron(ones(Nc,1),umax);
    Ut   = kron(ones(Nc,1),um);
%----(1) A*x<=b----------%
    A_t=zeros(Nc,Nc);
    for p=1:1:Nc
        for q=1:1:Nc
            if p >= q 
                A_t(p,q)=1;
            else 
                A_t(p,q)=0;
            end
        end 
    end 
    A_cell=cell(2,1);
    A_cell{1,1} = A_t;
    A_cell{2,1} = -A_t;
    A=cell2mat(A_cell);  
    b_cell=cell(2, 1);
    b_cell{1,1} = Umax - Ut; 
    b_cell{2,1} = -Umin + Ut;
    b=cell2mat(b_cell);   
%----(2) Aeq*x=beq----------%
    Aeq = [];
    beq = [];
%----(3) lb=<x<=ub----------%
    lb=kron(ones(Nc,1),-dumax);
    ub=kron(ones(Nc,1),dumax);
